#!/bin/bash

# Catalyst Slate Deployment Helper Script

cd "$(dirname "$0")"

echo "🚀 Starting Catalyst Slate Deployment..."
echo ""

# Check if dist folder exists
if [ ! -d "dist" ]; then
    echo "❌ Error: dist folder not found. Please run 'slyte serve' or 'slyte build' first."
    exit 1
fi

echo "✅ Found dist folder"
echo ""

# Set the Slate app name
SLATE_APP_NAME="zcatcomponents"
FRAMEWORK="static"

echo "📋 Configuration:"
echo "  App Name: $SLATE_APP_NAME"
echo "  Framework: $FRAMEWORK"
echo "  Source: ./dist"
echo ""

# Create .catalyst directory if it doesn't exist
mkdir -p .catalyst

# Create the slate-config.toml file
cat > .catalyst/slate-config.toml << EOF
# Auto-generated by deploy script
framework = "$FRAMEWORK"
deployment_name = "default"
deployment_source = "./dist"
EOF

echo "✅ Created Slate configuration"
echo ""

# Try to deploy
echo "🔄 Attempting deployment..."
catalyst deploy

if [ $? -eq 0 ]; then
    echo ""
    echo "✅ Deployment successful!"
    echo "🌐 Your app is available at: https://$SLATE_APP_NAME.onslate.in"
else
    echo ""
    echo "⚠️  Deployment encountered an issue."
    echo ""
    echo "Troubleshooting steps:"
    echo "1. Verify Slate app '$SLATE_APP_NAME' exists in Catalyst console"
    echo "2. Try: catalyst slate:link --name $SLATE_APP_NAME --framework $FRAMEWORK"
    echo "3. Then run: catalyst deploy"
    echo ""
fi
